    zor: [
{s:"HbA1c %7 değeri uzun vadeli kan şekeri yönetimi açısından ne ifade eder?",a:0,c:["Son 2-3 ayın ortalama kan glukozunun yaklaşık 154 mg/dL olduğunu, diyabet sınır kontrolünde olduğunu","Normal bir değer olduğunu","Tip 1 diyabet tanısını kesinleştirdiğini","İnsülin tedavisine gerek olmadığını"],x:"ADA, diyabetli hastalarda HbA1c hedefini genel olarak <%7 olarak belirlemiştir; %7 üstü değerler uzun vadeli komplikasyon riskini artırır."},
{s:"RAAS (renin-anjiyotensin-aldosteron sistemi) kan basıncını nasıl düzenler?",a:0,c:["Böbrek hipoperfüzyonunda renin salgılanır; anjiyotensin II vazokonstrüksiyon ve aldosteron salgısıyla sodyum-su tutulumunu artırarak basıncı yükseltir","Kalp atışını doğrudan hızlandırarak basıncı artırır","Böbrekleri bypass ederek kan hacmini azaltır","Yalnızca akut streste aktive olur"]},
{s:"Hemoglobindeki oksijen taşıma işlevinde hangi metal iyonu görev alır?",a:0,c:["Demir (Fe²⁺)","Çinko (Zn²⁺)","Bakır (Cu²⁺)","Magnezyum (Mg²⁺)"],x:"Hemoglobindeki her heme grubunda bir Fe²⁺ iyonu bulunur; dört heme grubu dört oksijen molekülü taşır."},
{s:"Sitokrom c'nin mitokondriyal apoptoz yolağındaki rolü nedir?",a:0,c:["Mitokondri dış zarından sitozole geçerek apoptozom oluşumunu başlatır ve kaspaz-9'u aktive eder","Mitokondri zarının bütünlüğünü korur","ATP sentezini hızlandırır","Antioksidan savunmayı koordine eder"]},
{s:"mRNA aşılarının (COVID-19 örneği) çalışma mekanizması nedir?",a:0,c:["Hücre içinde viral protein antijeni üretilmesini sağlayan genetik talimatları verir; bağışıklık tepkisi bu proteine karşı gelişir","Canlı zayıflatılmış virüs içerir","Viral DNA'yı konakçı genomuna entegre eder","Hazır antikor içerir"],x:"mRNA aşıları hücre çekirdeğine girmez; ribozomlar mRNA'yı okuyarak viral protein üretir, mRNA kısa sürede parçalanır."},
{s:"Kaspaz basamağı (caspase cascade) hangi hücresel süreçte merkezi rol oynar?",a:0,c:["Programlı hücre ölümü (apoptoz)","Hücre bölünmesi","Protein sentezi","DNA replikasyonu"]},
{s:"Telomer kısalması yaşlanmayla nasıl ilişkilidir?",a:0,c:["Her hücre bölünmesinde telomerler kısalır; kritik uzunluğa ulaştığında hücre bölünmeyi durdurup yaşlanır (senesens) veya ölür","Telomerler uzadıkça hücre yaşlanır","Telomer uzunluğu yaşlanmayla ilişkili değildir","Yalnızca kanser hücrelerinde telomer kısalması görülür"],x:"Blackburn ve Greider telomeri keşfettikleri için Nobel aldı. Telomeraz enzimi telomerleri uzatabilir; kanserde aşırı aktif, yaşlı hücrelerde ise susturulmuş durumdadır."},
{s:"P53 proteininin kanser biyolojisindeki önemi nedir?",a:0,c:["DNA hasarında hücre döngüsünü durduran veya apoptozu tetikleyen tümör baskılayıcı protein; mutasyonunda hücre kontrolsüz bölünür","Hücre büyümesini doğrudan uyaran proto-onkogen","Hücre yüzeyinde sinyal alan reseptör","Lenfosit farklılaşmasını düzenleyen transkripsiyon faktörü"]},
{s:"Niçin viral hastalıklarda antibiyotikler etkisizdir?",a:0,c:["Antibiyotikler bakteri hücre duvarı ve ribozomunu hedef alır; virüslerde bu yapılar yoktur","Virüsler antibiyotikleri hızla sindirir","Virüsler immün sistemi tamamen baskılar","Antibiyotikler viral genomu güçlendirir"],x:"Virüsler konak hücrenin makinesini kullanır; dolayısıyla bakteriye özgü antibiyotik hedefleri virüste bulunmaz."},
{s:"Kardiyojenik şokta temel fizyopatoloji nedir?",a:0,c:["Kalbin pompa kapasitesinin ciddi düşmesiyle kardiyak debi azalır; dokulara oksijen yetersizliği gelişir ve tablo kötüleşir","Kan hacminin ani azalması","Vazodilatasyon nedeniyle periferik direncin düşmesi","Pulmoner emboli yüzünden sağ kalp basıncının artması"]},
{s:"Aksiyon potansiyelinin refrakter dönemi neden önemlidir?",a:0,c:["Sinir ve kas liflerinin uyarılamadığı bu dönem sinyalin tek yönlü iletilmesini ve kalbin tetanostan korunmasını sağlar","Hücrenin enerji depoladığı dönemdir","Nörotransmitterlerin sentezlendiği dönemdir","Sodyum kanallarının açıldığı dönemdir"],x:"Mutlak refrakter dönemde hiçbir uyaran yeni potansiyel oluşturamaz; kalp sürekli kasılmaz ve bilinçli impuls iletimi mümkün olur."},
{s:"CAR-T hücre tedavisinin kanser tedavisindeki mekanizması nedir?",a:0,c:["Hastanın T hücreleri genetik olarak modifiye edilerek tümör antijeni tanıyan kimerik antijen reseptörleri eklenir","Kemoterapi ilaçları T hücrelerine bağlanarak taşınır","Tümör küçüldükten sonra T hücreleri aktive olur","Tümör baskılayıcı genler viral vektörle hücreye eklenir"]},
{s:"DNA metilasyonu epigenetikte ne anlama gelir?",a:0,c:["CpG bölgelerindeki sitozine metil grubu eklenerek gen ifadesinin DNA dizisi değişmeksizin baskılanması","DNA baz sıralamasını değiştiren kimyasal süreç","Histon proteinlerinin modifikasyonu","RNA'nın DNA'ya geri dönüşümü"]},
{s:"Farmakokinetik 'yarılanma ömrü' kavramı ne anlama gelir?",a:0,c:["Bir ilacın kan düzeyinin yarıya düştüğü süre; doz aralığını belirler","İlacın biyoyararlanım oranı","İlacın karaciğerden ilk geçiş metabolizması","İlacın protein bağlanma oranı"],x:"Beş yarılanma ömründe ilaç %97 oranında elimine olur; bu uzun etkili ilaçlarda birikim riskini açıklar."},
{s:"Kompleman sistemi immün yanıtta nasıl işlev görür?",a:0,c:["Antijen-antikor komplekslerine bağlanarak membran atak kompleksi oluşturur, fagositozu güçlendirir ve inflamasyonu tetikler","Yalnızca adaptif immüniteyi aktive eder","Antikor üretimini doğrudan düzenler","T hücrelerinin farklılaşmasını sağlar"]},
{s:"Glutatyonun hücresel antioksidan savunmadaki rolü nedir?",a:0,c:["Reaktif oksijen türlerini nötralize eden ve karaciğerde toksin konjügasyonunu sağlayan tripeptit","Mitokondrinin elektron taşıyıcısı","ATP sentezinde kofaktör","DNA'nın metilasyonunu engelleyen madde"],x:"İndirgenmiş glutatyon (GSH) peroksitleri ve elektrofilleri temizler; karaciğer detoks yolağında merkezi öneme sahiptir."},
{s:"Ters transkriptaz enzimi hangi virüs sınıfı için tipiktir ve HIV tedavisinde neden hedeflenir?",a:0,c:["Retrovirüsler; RNA'yı DNA'ya çevirir — inhibisyonu virüsün konak genomuna entegrasyonunu önler","DNA virüsleri; DNA replikasyonunu sağlar","Bakteriyofajlar; RNA parçalama enzimi","Adenovirüsler; kapsid oluşturucu enzim"]},
{s:"NF-κB yolağı inflamasyonda nasıl bir rol üstlenir?",a:0,c:["Pek çok inflamatuar gen ve sitokin üretimini tetikleyen transkripsiyon faktörü; kronik aktivasyonu otoimmün ve kanserle ilişkili","Apoptozu doğrudan başlatan sinyal proteini","Yalnızca viral enfeksiyonlarda aktive olan yolak","İmmün toleransı artıran düzenleyici yolak"]},
{s:"Difüzyon kapasitesi (DLCO) akciğer fonksiyon testinde ne ölçer?",a:0,c:["Alveoler-kapiler zardan gazın geçiş verimliliğini; amfizem ve pulmoner fibroziste düşer","Total akciğer kapasitesini","Zorlu ekspirasyon hacmini (FEV1)","Alveollerdeki hava miktarını"],x:"DLCO için karbonmonoksit kullanılır; amfizemde alveol yüzeyinin azalması, fibroziste ise zarın kalınlaşması DLCO'yu düşürür."},
{s:"Hipoksi eritropoetin salınımını nasıl etkiler?",a:0,c:["Böbrekteki HIF-1α aktivasyonu EPO salgısını artırır; EPO kemik iliğini daha fazla kırmızı hücre üretmeye uyarır","Hipoksi doğrudan kemik iliğini uyarır, EPO devreye girmez","Dalak EPO üretimini artırır","Hipokside EPO azalır"],x:"HIF-1α (hipoksi uyarımlı faktör), oksijen düşüklüğünde kararlı hale gelir ve EPO genini aktive ederek eritropoezi artırır."},
{s:"CRISPR-Cas9 gen düzenleme sisteminin tıbbi potansiyeli nedir?",a:0,c:["Hastalık yapan mutasyonları DNA düzeyinde düzelterek genetik hastalıkları tedavi etme potansiyeli; orak hücre anemisi için klinik çalışmalar tamamlandı","Yalnızca laboratuvar araştırmalarında kullanılır","Hücre dışında DNA'yı keser, hücreye girmez","Epigenetik değişiklikleri geri alır"],x:"2023'te FDA, CRISPR bazlı exa-cel ürününü orak hücre anemisi tedavisi için onayladı; bu tıp tarihinde tarihsel bir ilktir."},
{s:"Telomeraz aktivasyonu ile kanser gelişimi arasındaki ilişki nedir?",a:0,c:["Kanserde telomeraz aşırı aktif olarak telomer kısalmasını önler; hücreler sınırsız bölünür","Kanser hücreleri telomerazı baskılar","Telomeraz yalnızca embriyo hücrelerinde aktif","Telomeraz aktivasyonu tümör baskılayıcı etki gösterir"]},
{s:"Mitokondriyal DNA'nın nükleer DNA'dan farkı nedir?",a:0,c:["Yalnızca anneden kalıtılır, daireseldir ve 37 gen kodlar; mutasyon oranı nükleer DNA'dan yüksektir","İki ebeveynden eşit oranda kalıtılır","Histon proteinleri tarafından sarılıdır","Çift sarmaldır ve doğrusal yapıdadır"],x:"Mitokondriyal kalıtım Mendel kurallarına uymaz; mtDNA mutasyonları MELAS, MERRF gibi nadir mitokondriyal hastalıklara yol açar."},
{s:"Graft-versus-host hastalığı (GvHH) kök hücre naklinde neden gelişir?",a:0,c:["Donör T hücrelerinin alıcının dokularını yabancı antijen olarak tanıyıp saldırması","Alıcı bağışıklık sisteminin naklolunan hücreleri reddetmesi","Donörün kemik iliğinin alıcıda büyüyememesi","İmmunsüpresyonun yetersiz kalması"],x:"GvHH akut veya kronik seyreder; şiddetli vakalar karaciğer, bağırsak ve deriyi etkiler ve kök hücre transplantasyonunun en ciddi komplikasyonlarından biridir."},
{s:"Farmakogenomik neden kişiselleştirilmiş tıp için önemlidir?",a:0,c:["CYP450 enzim polimorfizmleri gibi genetik varyasyonlar ilaç metabolizmasını değiştirerek etkinlik ve toksisite profilini farklılaştırır","Tüm insanlar ilaçlara aynı tepkiyi verir","Farmakogenomik yalnızca kemoterapide uygulanır","Genetik test ilaç seçiminde yetersiz bilgi sağlar"],x:"Kodein, CYP2D6 enzimiyle morfine dönüşür; yavaş metabolize edenlerde etkisizken hızlı metabolize edenlerde toksik doz birikebilir."},
{s:"Biyofilm oluşturan bakterilerin antibiyotik direnci hangi mekanizmaya dayanır?",a:0,c:["Ekstraselüler polimer matriks hem antibiyotik difüzyonunu engeller hem de persister hücre oluşumunu artırır","Bakteriler antibiyotikleri aktif olarak pompalar","Biyofilm içindeki bakteriler sporlaşır","Biyofilm yalnızca zayıf antibiyotiklere karşı direnç sağlar"]},
{s:"Histon asetilasyonu gen ifadesini nasıl etkiler?",a:0,c:["Nükleozom yapısını gevşetir; DNA'ya transkripsiyon faktörlerinin erişimini artırarak gen ifadesini aktive eder","Histon asetilasyonu DNA'nın metilasyonunu sağlar","Gen ifadesini her koşulda baskılar","mRNA'nın kararlılığını artırır"]},
{s:"Multipl skleroz hangi yapıyı etkiler ve bu nasıl belirtilere neden olur?",a:0,c:["Merkezi sinir sistemindeki miyelin kılıfı; impuls iletimi bozulur, etkilenen bölgeye göre görme kaybı, felç ve denge bozukluğu görülür","Periferik sinir kılıfları; yalnızca el-ayak uyuşması","Kas hücre zarı; kas güçsüzlüğü","Astrositler; bilinç bozukluğu"]},
{s:"Glukoneogenez ile glikoliz arasındaki temel fark nedir?",a:0,c:["Glukoneogenez karaciğerde glikoz dışı öncülerden (laktat, amino asit, gliserol) glikoz sentezler; glikoliz glikozu pirüvata yıkar","İkisi aynı yolun ileri ve geri reaksiyonlarıdır","Glukoneogenez yalnızca kas dokusunda gerçekleşir","Glikoliz mitokondride olur, glukoneogenez sitozolde"],x:"Glukoneogenezin 3 kontrol noktası glikolizi aşar; bu enzimler uzun açlık durumunda kan şekerini korumada kritiktir."},
{s:"İmmün kontrol noktası inhibitörleri (PD-1/PD-L1 blokajı) kansere karşı nasıl çalışır?",a:0,c:["Tümör hücrelerinin T hücresini susturmak için kullandığı 'kaçış' sinyali bloke edilerek T hücrelerinin tümörü öldürme kapasitesi geri kazandırılır","Direkt tümör hücrelerini öldürür","Antikor üretimini artırır","Kemoterapi ilaçlarının tümöre taşınmasını sağlar"],x:"Pembrolizumab ve nivolumab PD-1 blokörüdür; melanom ve akciğer kanserinde uzun süreli yanıtlar göstererek onkolojide paradigmayı değiştirdi."},
{s:"Miyelinasyonun sinir iletimindeki etkisi nedir?",a:0,c:["Saltatorik iletimi sağlayarak aksiyon potansiyelinin Ranvier düğümlerinden atlayarak çok daha hızlı yayılmasını mümkün kılar","Sinir liflerinin kalınlığını artırarak iletimi yavaşlatır","Nörotransmitter salınımını düzenler","Geri besleme mekanizmasını engeller"]},
{s:"Otofajinin hücresel sağlıktaki rolü nedir?",a:0,c:["Lizozomlar aracılığıyla hasarlı organelleri ve protein agregatlarını sindirerek hücresel kalite kontrolü sağlar; baskılanması nörodejeneratif hastalıklarla ilişkilidir","Hücrenin bölünmesini tetikleyen sinyal yolağıdır","Mitokondriyal ATP üretimini artırır","DNA hasarını tamir eden süreçtir"],x:"Yoshinori Ohsumi otofajinin mekanizmalarını açıkladığı için 2016 Nobel Tıp Ödülü'nü aldı."},
{s:"tPA (doku plazminojen aktivatörü) hangi durumda kullanılır?",a:0,c:["Akut iskemik inmede ilk 4,5 saat içinde fibrinoliz için","Kalp krizi sonrası kardiyak rehabilitasyonda","Kanama bozukluklarında koagülasyon için","Kronik tromboz tedavisinde uzun süre kullanımda"]},
{s:"HMG-CoA redüktaz enzimi neden statinlerin hedefidir?",a:0,c:["Kolesterol biyosentezinin hız sınırlayıcı adımını kataliz eder; inhibisyonu karaciğerin LDL reseptör ekspresyonunu artırarak kan LDL'sini düşürür","Kolesterolü safra asidine dönüştüren son enzimdir","Yalnızca bağırsak hücrelerinde aktiftir","Trigliserit sentezinde görev alır"],x:"Statinler HMG-CoA redüktazı kompetitif inhibe eder; karaciğer LDL'yi kandan daha fazla temizlemek için daha fazla LDL reseptörü ifade eder."},
{s:"Septik şokta sitokin fırtınası nasıl organ yetmezliğine yol açar?",a:0,c:["Aşırı pro-inflamatuar sitokinler (TNF-α, IL-6) endotel hasarı ve mikrosirkülasyon bozukluğuna neden olur; bu çoklu organ yetmezliğine gider","Yalnızca karaciğeri etkiler","Sitokinler direkt patojen öldürür","Düşük sitokin düzeyi organ yetmezliğine yol açar"],x:"COVID-19 ağır vakalarında da 'sitokin fırtınası' tanımlanmıştır; IL-6 reseptör blokörü tocilizumab bu tabloda kullanılır."},
{s:"Beyin görüntülemede fMRI nasıl çalışır?",a:0,c:["Nöronal aktiviteye bağlı lokal kan akışı ve oksijen kullanımını (BOLD sinyali) ölçerek aktif beyin bölgelerini saptar","X ışınlarıyla beyin dokusunun yoğunluğunu ölçer","Elektriksel aktiviteyi milisaniye düzeyinde kaydeder","Radyoaktif işaretleyici ile nörotransmitter seviyesini ölçer"]},
{s:"Poligenik risk skoru (PRS) tıbbi genetikte ne anlama gelir?",a:0,c:["Binlerce küçük etkili genetik varyantı toplayarak bireyin belirli bir hastalığa yatkınlığını tahmin eden kümülatif skor","Tek gen mutasyonuna dayalı hastalık tahmini","Ailede görülen hastalıkların sayısını ölçen skor","Epigenetik değişiklikleri hesaba katan genetik analiz"]},
{s:"Akciğer surfaktanı neden prematur bebeklerde hayati önem taşır?",a:0,c:["Yüzey gerilimini düşürerek alveol kollapsını önler; erken doğanlarda eksikliği respiratuvar distres sendromuna yol açar","Akciğerleri mikroplardan korur","Kanın oksijenasyonunu artıran biyokimyasal madde","Akciğer büyümesini uyaran büyüme faktörü"],x:"Surfaktan ~34. gestasyonel haftadan sonra yeterince üretilir; eksikliğinde ekzojen surfaktan tedavisi hayat kurtarıcıdır."},
{s:"Yüksek doz steroid tedavisinin bağışıklık sistemine etkisi neden komplikasyon riski taşır?",a:0,c:["NF-κB baskılanmasıyla sitokin üretimi azalır, lenfosit sayısı düşer; bu immunosüpresyon fırsatçı enfeksiyonlara kapı aralar","Bağışıklığı artırarak otoimmün hastalığa yol açar","Yalnızca alerjik tepkileri baskılar","Steroidler yalnızca anti-inflamatuar, immunosüpresif değil"],x:"Uzun süreli yüksek doz steroid; Cushing bulguları, osteoporoz, hiperglisemi ve fırsatçı enfeksiyon riskini doğurur."},
{s:"Warburg etkisi kanser metabolizmasını nasıl tanımlar?",a:0,c:["Kanser hücrelerinin oksijen varlığında bile glikolizi tercih etmesi (aerobik glikoliz), laktat üretmesi ve hızlı enerji üretimiyle biyomolekül sentezlemesi","Kanser hücrelerinin oksidatif fosforilasyonu artırması","Tümörün yağ asitlerini tercih etmesi","Kanser hücrelerinin glikozu reddedip amino asitleri kullanması"]},
{s:"Nöroplastisite beyin sağlığı açısından neden önemlidir?",a:0,c:["Beynin deneyim ve öğrenmeyle sinaptik bağlantılarını yeniden düzenleyebilmesi; felç rehabilitasyonu ve öğrenme süreçlerinde temel rol oynar","Beynin nöron kaybını tamamen önlemesi","Beynin yeni nöronlar üretmemesi","Beynin yaşla birlikte sabit bir yapıya kavuşması"],x:"Erişkin nörogenezi hipokampusta kanıtlanmıştır; egzersiz, öğrenme ve meditasyonun nöroplastisiteyi artırdığı gösterilmiştir."},
{s:"Mikroglia beyin bağışıklık savunmasında nasıl işlev görür?",a:0,c:["Merkezi sinir sisteminin doku makrofajları olarak patojenleri ve hücre artıklarını temizler; nörodejeneratif hastalıklarda aşırı aktivasyonu zararlı olabilir","Miyelin sentezinden sorumlu destek hücreleridir","Nörotransmitter salgılayan hücrelerdir","Kan-beyin bariyerinin yapısal bileşenidirler"]},
{s:"Hücre döngüsünün G1/S kontrol noktasında ne denetlenir?",a:0,c:["DNA hasarı, hücre büyüklüğü ve büyüme faktörü yeterliliği; yetersizlikte hücre S fazına geçemez","Mitoz iğinin doğru kurulumu","Sitokinezin tamamlanması","Organellerin ikiye bölünmesi"],x:"Rb proteini ve p53, bu kontrol noktasının ana düzenleyicileridir; kanserde bu düzenleyiciler sık mutasyona uğrar."}
    ]
